sql:
SELECT version_number
FROM company_versions
WHERE company_id = 0;

SELECT company_id, AVG(rating) AS average_rating, COUNT(*) AS review_count
FROM company_reviews
GROUP BY company_id;

external_knowledge:
- A 'top-performing company' refers to a company with higher revenue than the average revenue of its industry; 
- 'Partnerships' and 'collaborations' are types of business relationships; 
- 'Access counts' represent the number of times a company's profile was accessed.

sql:
SELECT DISTINCT company_id
FROM company_reviews
WHERE is_recommended = 1;

SELECT rating, usefulness
FROM company_reviews
ORDER BY rating DESC;

SELECT company_id, AVG(metric_value) as avg_metric_value, COUNT(*) as total_metrics, MAX(metric_date) as latest_metric_date
FROM company_metrics
GROUP BY company_id;
